INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 20, 20001, 320, "", 0, "", 0, 23001, 10, 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 40011, 321, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 125801, "リリ", 1, 24001, 1, 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 40011, 322, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 126001, "クリア", 1, 24001, 2, 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 40011, 323, "んーと。\nこれ、あげる。\nはい", 126101, "プレシア", 1, 24001, 3, 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 40011, 324, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 125801, "リリ", 2, 24001, 4, 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 40011, 325, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 126001, "クリア", 2, 24001, 5, 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (0, 1, 40011, 326, "お兄。\nきてくれて、うれしい", 126101, "プレシア", 2, 24001, 6, 2);
INSERT INTO `v1_d62602f5a5130581a76698d121ecda27b9e83113491990bf794fbe61b973fd8f` VALUES (532001, 100, 80009, 327, "", 0, "", 0, 91002, 1, 8);
